import{_ as e,c as a,o as t,a4 as s}from"./chunks/framework.nQaBHiNx.js";const f=JSON.parse('{"title":"第一章 原子的运动","description":"","frontmatter":{"permalink":"/physics/the-feynman-lectures-on-physics-1/01.html"},"headers":[],"relativePath":"physics/the-feynman-lectures-on-physics-1/01-第一章 原子的运动.md","filePath":"physics/the-feynman-lectures-on-physics-1/01-第一章 原子的运动.md"}'),n={name:"physics/the-feynman-lectures-on-physics-1/01-第一章 原子的运动.md"},r=s('<h1 id="第一章-原子的运动" tabindex="-1">第一章 原子的运动 <a class="header-anchor" href="#第一章-原子的运动" aria-label="Permalink to &quot;第一章 原子的运动&quot;">​</a></h1><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>大自然整体的每一部分始终不过是对整个真理——或者说，对于我们至今所了解的整个真理——的<strong>逼近</strong>。实际上，人们知道的每件事都只是某种近似，因为我们懂得，到目前为止，<strong>我们确实还不知道所有的定律</strong>。因此，我们学习一些东西，正是为了要重新忘掉它们，或者更确切地说是为了改正以前对它们的谬见。</p><p>科学的原则或者简直可称为科学的定义为：<strong>实验是一切知识的试金石</strong>。实验是科学“真理”的唯一鉴定者。但什么是知识的源泉呢？那些要检验的定律又是从何而来的呢？从某种意义上来说，实验为我们提供了种种线索，因此可以说是实验本身促成了这些定律的产生。但是，要从这些线索中作出重大的判断，还需要有丰富的想象力对蕴藏在所有线索背后的图像进行猜测，然后再用实验来验证我们猜测的究竟对不对。</p><h2 id="物质是由原子构成的" tabindex="-1">物质是由原子构成的 <a class="header-anchor" href="#物质是由原子构成的" aria-label="Permalink to &quot;物质是由原子构成的&quot;">​</a></h2><p>假如由于某种大灾难，所有的科学知识都丢失了，只有一句话可以传给下一代，那么我相信这句话是：所有的物体都是由原子构成的——这些原子是一些小小的粒子，它们一直不停地运动着，当彼此略微离开时相互吸引，当彼此过于挤紧时又互相排斥。</p>',6),o=[r];function _(c,h,i,l,p,d){return t(),a("div",null,o)}const u=e(n,[["render",_]]);export{f as __pageData,u as default};
